+                } else {
+                    xi * (1.0 + yi).ln()
+                }
+            })
+            .collect();
+
+        let out = self
+            .tensor_tape
+            .leaf(values, x_meta.shape().to_vec(), false)?;
+        self.runtime.ledger_mut().record(
+            EvidenceKind::Dispatch,
+            format!("xlog1py x={} y={} out={}", x.0, y.0, out.0),
+        );
+        Ok(out)
+    }
