+        let two_pi = 2.0 * std::f64::consts::PI;
+        let mut re_out = Vec::with_capacity(out_len);
+        let mut im_out = Vec::with_capacity(out_len);
+
+        for k in 0..out_len {
+            let mut re = 0.0;
+            let mut im = 0.0;
+            for (nn, &xn) in x.iter().enumerate() {
+                let angle = -two_pi * k as f64 * nn as f64 / fft_len as f64;
+                re += xn * angle.cos();
+                im += xn * angle.sin();
+            }
+            re_out.push(re);
+            im_out.push(im);
