+        for k in 0..freq_len.min(out_len) {
+            re_full[k] = vals[k * 2];
+            im_full[k] = vals[k * 2 + 1];
+        }
+        // Mirror: X[N-k] = conj(X[k])
+        for k in 1..freq_len.min(out_len) {
+            let mirror = out_len - k;
+            if mirror < out_len && mirror != k {
+                re_full[mirror] = vals[k * 2];
+                im_full[mirror] = -vals[k * 2 + 1];
